INSERT INTO workflows (company_id, name, trigger, graph, status) VALUES ('00000000-0000-0000-0000-000000000001','Bug-to-Fix','{"type": "event", "source": "support_or_monitoring", "event": "bug_reported"}'::jsonb,'{"nodes": [{"id": "1", "agent": "qa", "action": "triage_confirm_reproduce_assign_severity"}, {"id": "2", "agent": "dev", "action": "fix_backend_or_frontend"}, {"id": "3", "condition": "security_bug", "true": "4", "false": "5"}, {"id": "4", "agent": "security", "action": "review_fix"}, {"id": "5", "agent": "qa", "action": "verify_fix_regression_test"}, {"id": "6", "condition": "severity in [P0,P1]", "true": "7", "false": "8"}, {"id": "7", "agent": "cto", "action": "approve"}, {"id": "8", "agent": "devops", "action": "deploy"}, {"id": "9", "agent": "support", "action": "notify_customer"}]}'::jsonb,'active');
INSERT INTO workflows (company_id, name, trigger, graph, status) VALUES ('00000000-0000-0000-0000-000000000001','Daily Standup','{"type": "cron", "schedule": "0 9 * * 1-5"}'::jsonb,'{"nodes": [{"id": "1", "agent": "orchestrator", "action": "collect_team_status"}, {"id": "2", "agent": "orchestrator", "action": "aggregate_blockers"}, {"id": "3", "agent": "orchestrator", "action": "generate_standup_report"}, {"id": "4", "agent": "orchestrator", "action": "notify_team_escalate_blockers"}]}'::jsonb,'active');
INSERT INTO workflows (company_id, name, trigger, graph, status) VALUES ('00000000-0000-0000-0000-000000000001','Emergency Escalation','{"type": "event", "source": "monitoring", "event": "critical_alert"}'::jsonb,'{"nodes": [{"id": "1", "agent": "devops", "action": "acknowledge_alert"}, {"id": "2", "agent": "devops", "action": "assess_impact"}, {"id": "3", "condition": "is_critical", "true": "4", "false": "5"}, {"id": "4", "agent": "orchestrator", "action": "page_oncall_ceo_cto"}, {"id": "5", "agent": "devops", "action": "begin_fix"}, {"id": "6", "agent": "devops", "action": "deploy_fix"}, {"id": "7", "agent": "qa", "action": "verify_resolution"}, {"id": "8", "agent": "devops", "action": "post_mortem"}]}'::jsonb,'active');
INSERT INTO workflows (company_id, name, trigger, graph, status) VALUES ('00000000-0000-0000-0000-000000000001','Lead-to-Order','{"type": "event", "source": "CRM", "event": "new_lead"}'::jsonb,'{"nodes": [{"id": "1", "agent": "research", "action": "enrich_lead_data"}, {"id": "2", "agent": "crm", "action": "score_qualify_lead"}, {"id": "3", "condition": "score > 70", "true": "4", "false": "end"}, {"id": "4", "agent": "sales", "action": "send_intro_schedule_demo"}, {"id": "5", "condition": "interested", "true": "6", "false": "end"}, {"id": "6", "agent": "sales", "action": "generate_proposal"}, {"id": "7", "agent": "finance", "action": "review_pricing_apply_discounts"}, {"id": "8", "condition": "deal_value > 50000", "true": "9", "false": "10"}, {"id": "9", "agent": "ceo", "action": "approve"}, {"id": "10", "agent": "workflow", "action": "create_order_notify_inventory_invoice"}, {"id": "11", "agent": "support", "action": "onboarding_sequence"}]}'::jsonb,'active');
INSERT INTO workflows (company_id, name, trigger, graph, status) VALUES ('00000000-0000-0000-0000-000000000001','Monthly Financial Close','{"type": "cron", "schedule": "0 8 1 * *"}'::jsonb,'{"nodes": [{"id": "1", "agent": "finance", "action": "collect_all_transactions"}, {"id": "2", "agent": "finance", "action": "reconcile_bank_statements"}, {"id": "3", "agent": "finance", "action": "generate_financial_statements"}, {"id": "4", "agent": "cfo", "action": "review_approve_statements"}, {"id": "5", "agent": "finance", "action": "prepare_tax_filing_if_applicable"}, {"id": "6", "agent": "ceo", "action": "board_report"}]}'::jsonb,'active');
INSERT INTO workflows (company_id, name, trigger, graph, status) VALUES ('00000000-0000-0000-0000-000000000001','Recruitment','{"type": "manual", "source": "ceo", "action": "approve_job_req"}'::jsonb,'{"nodes": [{"id": "1", "agent": "hr", "action": "create_jd_post_job_boards"}, {"id": "2", "agent": "research", "action": "source_candidates"}, {"id": "3", "agent": "hr", "action": "screen_cvs_schedule_interviews"}, {"id": "4", "agent": "department_head", "action": "interview_score"}, {"id": "5", "agent": "hr", "action": "collect_feedback_make_offer"}, {"id": "6", "condition": "compensation > 10000", "true": "7", "false": "8"}, {"id": "7", "agent": "cfo", "action": "approve_compensation"}, {"id": "8", "condition": "compensation > 20000", "true": "9", "false": "10"}, {"id": "9", "agent": "ceo", "action": "final_approval"}, {"id": "10", "agent": "hr", "action": "send_offer_onboarding_checklist"}]}'::jsonb,'active');
